import{_ as e,o as a,c as i,a2 as r}from"./chunks/framework.ufzXw1qY.js";const u=JSON.parse('{"title":"Migrations Overview — OpenSIN-AI Migration Guides","description":"","frontmatter":{},"headers":[],"relativePath":"migrations/overview.md","filePath":"migrations/overview.md"}'),o={name:"migrations/overview.md"};function n(s,t,l,d,g,h){return a(),i("div",null,[...t[0]||(t[0]=[r('<h1 id="migrations-overview-—-opensin-ai-migration-guides" tabindex="-1">Migrations Overview — OpenSIN-AI Migration Guides <a class="header-anchor" href="#migrations-overview-—-opensin-ai-migration-guides" aria-label="Permalink to &quot;Migrations Overview — OpenSIN-AI Migration Guides&quot;">​</a></h1><p><strong>Status:</strong> Active <strong>Owner:</strong> Team Coding</p><hr><h2 id="what-are-migrations" tabindex="-1">What Are Migrations? <a class="header-anchor" href="#what-are-migrations" aria-label="Permalink to &quot;What Are Migrations?&quot;">​</a></h2><p>Migration guides document the process of transitioning between versions, architectures, or configurations in the OpenSIN-AI ecosystem. They ensure fleet-wide consistency and prevent breakage during upgrades.</p><hr><h2 id="migration-categories" tabindex="-1">Migration Categories <a class="header-anchor" href="#migration-categories" aria-label="Permalink to &quot;Migration Categories&quot;">​</a></h2><h3 id="_1-opencode-config-migrations" tabindex="-1">1. OpenCode Config Migrations <a class="header-anchor" href="#_1-opencode-config-migrations" aria-label="Permalink to &quot;1. OpenCode Config Migrations&quot;">​</a></h3><p>Changes to <code>~/.config/opencode/opencode.json</code> that require fleet-wide sync:</p><ul><li>Model updates or additions</li><li>Provider configuration changes</li><li>Plugin additions/removals</li><li>MCP server registration changes</li></ul><p><strong>Sync command:</strong> <code>sin-sync</code> (pushes Mac → OCI VM → HF VMs)</p><h3 id="_2-agent-migrations" tabindex="-1">2. Agent Migrations <a class="header-anchor" href="#_2-agent-migrations" aria-label="Permalink to &quot;2. Agent Migrations&quot;">​</a></h3><p>Updating agent configurations across teams:</p><ul><li>Team member additions/removals</li><li>Model reassignments</li><li>Capability registry updates</li><li>Telegram bot re-registration</li></ul><h3 id="_3-database-migrations" tabindex="-1">3. Database Migrations <a class="header-anchor" href="#_3-database-migrations" aria-label="Permalink to &quot;3. Database Migrations&quot;">​</a></h3><p>Supabase schema changes:</p><ul><li>New tables for agent pools</li><li>Column additions/modifications</li><li>Index optimizations</li><li>Data migrations</li></ul><h3 id="_4-infrastructure-migrations" tabindex="-1">4. Infrastructure Migrations <a class="header-anchor" href="#_4-infrastructure-migrations" aria-label="Permalink to &quot;4. Infrastructure Migrations&quot;">​</a></h3><p>OCI VM, Cloudflare Workers, HF Space changes:</p><ul><li>Container image updates</li><li>Proxy configuration changes</li><li>SSL/TLS certificate rotations</li><li>Domain migrations</li></ul><hr><h2 id="migration-protocol" tabindex="-1">Migration Protocol <a class="header-anchor" href="#migration-protocol" aria-label="Permalink to &quot;Migration Protocol&quot;">​</a></h2><ol><li><strong>Announce</strong>: Create GitHub Issue with migration details</li><li><strong>Test</strong>: Apply migration on staging/dev environment</li><li><strong>Document</strong>: Update migration guide with steps and rollback plan</li><li><strong>Execute</strong>: Run migration during low-traffic window</li><li><strong>Verify</strong>: Run health checks across all fleet nodes</li><li><strong>Sync</strong>: Run <code>sin-sync</code> to propagate config changes</li></ol><hr><h2 id="rollback-procedure" tabindex="-1">Rollback Procedure <a class="header-anchor" href="#rollback-procedure" aria-label="Permalink to &quot;Rollback Procedure&quot;">​</a></h2><p>Every migration MUST have a rollback plan:</p><ol><li>Revert config changes from backup</li><li>Restore database from snapshot</li><li>Run <code>sin-sync</code> with previous config</li><li>Verify fleet health returns to baseline</li></ol><hr><h2 id="active-migrations" tabindex="-1">Active Migrations <a class="header-anchor" href="#active-migrations" aria-label="Permalink to &quot;Active Migrations&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Migration</th><th>Status</th><th>Date</th><th>Impact</th></tr></thead><tbody><tr><td><em>(none currently active)</em></td><td>—</td><td>—</td><td>—</td></tr></tbody></table><hr><h2 id="past-migrations" tabindex="-1">Past Migrations <a class="header-anchor" href="#past-migrations" aria-label="Permalink to &quot;Past Migrations&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Migration</th><th>Completed</th><th>Notes</th></tr></thead><tbody><tr><td>Antigravity Plugin Migration</td><td>2026-04</td><td>All fleet nodes updated to use Antigravity OAuth</td></tr><tr><td>Bun Package Manager Mandate</td><td>2026-03</td><td>npm permanently banned, bun enforced</td></tr><tr><td>Technology Sovereignty Mandate</td><td>2026-03</td><td>Camoufox/Playwright/Puppeteer/Selenium banned</td></tr></tbody></table><hr><h2 id="related" tabindex="-1">Related <a class="header-anchor" href="#related" aria-label="Permalink to &quot;Related&quot;">​</a></h2><ul><li><a href="/guide/deployment.html">sin-sync Documentation</a></li><li><a href="/guide/agent-configuration.html">OpenCode Config Guide</a></li><li><a href="/governance/overview.html">Governance Overview</a></li></ul><hr><h2 id="relevante-mandate" tabindex="-1">Relevante Mandate <a class="header-anchor" href="#relevante-mandate" aria-label="Permalink to &quot;Relevante Mandate&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Mandat</th><th>Priority</th><th>Regel</th></tr></thead><tbody><tr><td><strong>Bun-Only</strong></td><td>-1.5</td><td><code>bun install</code> / <code>bun run</code> statt npm</td></tr><tr><td><strong>Annahmen-Verbot</strong></td><td>-5.0</td><td>KEINE Diagnose ohne Beweis</td></tr><tr><td><strong>Test-Beweis-Pflicht</strong></td><td>0.0</td><td>KEIN &quot;Done&quot; ohne echten Test-Lauf</td></tr></tbody></table><p>→ <a href="/best-practices/code-quality.html">Alle Mandate</a></p>',40)])])}const m=e(o,[["render",n]]);export{u as __pageData,m as default};
